// Get all input items
const items = $input.all();

// Set default timezone to IST (India Standard Time) if not specified
const DEFAULT_TIMEZONE = "Asia/Kolkata"; 

// Current date/time reference
const now = new Date();
console.log(`Current UTC Time: ${now.toISOString()}`);
console.log(`Current IST Time: ${new Date().toLocaleString("en-US", {timeZone: "Asia/Kolkata"})}`);

// Loop through each item
for (const item of items) {
  // Get the values from the current item's JSON data
  const startTimeUTC = item.json.starttime;
  const endTimeUTC = item.json.endtime;

  // Use specified timezone or default to IST
  const targetTimeZone = item.json.timeZone || DEFAULT_TIMEZONE;

  // Add timezone to item for reference
  item.json.timeZone = targetTimeZone;

  // Basic validation: ensure the necessary fields exist
  if (!startTimeUTC || !endTimeUTC) {
    console.warn(`Skipping item due to missing time data. Item JSON: ${JSON.stringify(item.json)}`);
    item.json.conversionError = "Missing starttime or endtime";
    continue; // Move to the next item
  }

  try {
    // Log input times for debugging
    console.log(`Converting times for item: Start=${startTimeUTC}, End=${endTimeUTC}, Target TZ=${targetTimeZone}`);

    // --- Start Time Conversion ---
    // Parse the original UTC ISO string using Luxon
    const startDt = luxon.DateTime.fromISO(startTimeUTC, { zone: 'utc' });

    // Convert the DateTime object to the target timezone
    const startDtTargetZone = startDt.setZone(targetTimeZone);

    // Check if the conversion was valid
    if (!startDtTargetZone.isValid) {
      throw new Error(`Failed to convert start time. Reason: ${startDtTargetZone.invalidReason || 'Unknown'}`);
    }

    // Format the result back into an ISO string with the correct offset
    item.json.starttime = startDtTargetZone.toISO();

    // Add a human-readable version for easier debugging
    item.json.starttime_readable = startDtTargetZone.toLocaleString(luxon.DateTime.DATETIME_FULL);

    // --- End Time Conversion ---
    // Parse the original UTC ISO string using Luxon
    const endDt = luxon.DateTime.fromISO(endTimeUTC, { zone: 'utc' });

    // Convert the DateTime object to the target timezone
    const endDtTargetZone = endDt.setZone(targetTimeZone);

    // Check if the conversion was valid
    if (!endDtTargetZone.isValid) {
      throw new Error(`Failed to convert end time. Reason: ${endDtTargetZone.invalidReason || 'Unknown'}`);
    }

    // Format the result back into an ISO string with the correct offset
    item.json.endtime = endDtTargetZone.toISO();

    // Add a human-readable version for easier debugging
    item.json.endtime_readable = endDtTargetZone.toLocaleString(luxon.DateTime.DATETIME_FULL);

    // Calculate duration in minutes for reference
    const durationMinutes = endDtTargetZone.diff(startDtTargetZone, 'minutes').minutes;
    item.json.duration_minutes = Math.round(durationMinutes);

    // Optionally remove the error flag if conversion was successful this time
    delete item.json.conversionError;

    console.log(`Conversion successful: ${item.json.starttime_readable} to ${item.json.endtime_readable} (${item.json.duration_minutes} minutes)`);

  } catch (error) {
    console.error(`Error converting time for item: ${JSON.stringify(item.json)}. Error: ${error.message}`);
    // Add/update the error flag to the item's JSON
    item.json.conversionError = error.message;
  }
}

// Return the modified array of items
return items;

const escapeStringForJson = (str) => {
    return str
        .replace(/\\/g, '\\\\') // Escape backslashes
        .replace(/"/g, '\\"')    // Escape double quotes
        .replace(/\n/g, '\\n')   // Escape newlines
        .replace(/\r/g, '\\r')   // Escape carriage returns
        .replace(/\t/g, '\\t');  // Escape tabs
};

// Escape the notes field
$input.item.json.notes = escapeStringForJson($input.item.json.notes);

return $input.item;

