// Get the input data for the first item
const inputData = $input.first().json;
console.log("Input Data:", inputData); // Log input for debugging

// Access the message string from the correct path within the input structure.
// The input comes from the "Build Response Payload" node, which structures data under 'results'.
// Use optional chaining (?.) for safety in case the structure is not as expected.
let message = inputData.results?.[0]?.result;

// Check if the message was found and is a string
if (typeof message !== 'string') {
    console.error("Could not find the message string at inputData.results[0].result or it's not a string. Input:", inputData);
    // Return an object with an empty message or an error indicator
    return { message: "" }; // Or potentially throw an error: throw new Error("Input message not found or not a string");
}

// Start cleaning the message string

// 1. Replace the literal string "\\n" (backslash followed by n) with a space.
// This handles the newline representation seen in the input screenshot.
let cleanedMessage = message.replace(/\\n/g, ' ');

// 2. Remove spaces immediately surrounding colons (e.g., "Times : " becomes "Times:").
cleanedMessage = cleanedMessage.replace(/\s*:\s*/g, ':');

// 3. Replace sequences of multiple whitespace characters (including spaces from replaced \n)
// with a single space. Then, trim any leading or trailing whitespace from the result.
cleanedMessage = cleanedMessage.replace(/\s+/g, ' ').trim();

// Create the final output JSON object containing the cleaned message.
const output = {
    message: cleanedMessage
};

// Return the output object. This will be the output of the Code node.
return output;

function formatTimeSlot(dateString) {
  // Format options for date/time with Asia/Kolkata timezone
  const options = {
    timeZone: 'Asia/Kolkata',
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: 'numeric',
    hour12: true
  };

  // Create a formatter with timezone support
  const dateFormatter = new Intl.DateTimeFormat('en-IN', options);

  // Format the date/time string
  return dateFormatter.format(new Date(dateString));
}

// Process each slot and add formatted time strings to the result
const slots = $input.item.json.data.slots;
const formattedSlots = slots.map(slot => formatTimeSlot(slot.start));

// Attach formatted results to the output
$input.item.json.data.slots = formattedSlots;

return $input.item;

const flattenSlots = (data) => {
  // If data is missing or empty, return an empty array of slots
  if (!data) {
    return { slots: [] };
  }

  // data is an object whose keys are dates
  // each date key has an array of slot objects
  // we just need to flatten them all into one array
  const flattened = Object.values(data).flat();  // merges all arrays from each date key

  // Return a new object with a single 'slots' array
  return { slots: flattened };
};

// Then assign the flattened slots back to $input.item.json.data
$input.item.json.data = flattenSlots($input.item.json.data);
return $input.item;

// Complete Calendar Availability System
// Calendar Availability System

// Input data
const inputData = $input.all()[0].json.response || [];

// Define business hours in IST (India Standard Time)
const WORKDAY_START = 9; // 10 AM
const WORKDAY_END = 17;   // 5 PM
const SLOT_DURATION = 30; // 30 minutes

// UTC offset for IST is +5:30
const IST_OFFSET_HOURS = 5;
const IST_OFFSET_MINUTES = 30;

// Helper function to convert UTC to IST hours
const utcToIstHours = (utcHours) => {
  let istHours = utcHours + IST_OFFSET_HOURS;
  if (istHours >= 24) istHours -= 24;
  return istHours;
};

// Helper function to convert IST to UTC hours
const istToUtcHours = (istHours) => {
  let utcHours = istHours - IST_OFFSET_HOURS;
  if (utcHours < 0) utcHours += 24;
  return utcHours;
};

// Debug info
console.log('Business hours (IST):', `${WORKDAY_START}:00 - ${WORKDAY_END}:00`);
console.log('Business hours (UTC):', `${istToUtcHours(WORKDAY_START)}:${IST_OFFSET_MINUTES} - ${istToUtcHours(WORKDAY_END)}:${IST_OFFSET_MINUTES}`);

// Helper function to parse various date-time formats
const parseDateTime = (dateTimeStr) => {
  try {
    // If it's already an ISO string with T separator (2025-07-14T10:00:00+05:30)
    if (typeof dateTimeStr === 'string' && dateTimeStr.includes('T')) {
      return new Date(dateTimeStr);
    }

    // If it's a formatted string like "Monday, July 14, 2025, 10:00:00 GMT+5:30"
    if (typeof dateTimeStr === 'string' && dateTimeStr.includes(', ')) {
      // Split into parts for better parsing
      const parts = dateTimeStr.split(', ');

      // Try to handle different formats
      if (parts.length >= 3) {
        const datePart = parts.slice(0, 3).join(', ');
        let timePart, offsetPart;

        if (parts[3].includes('GMT')) {
          timePart = parts[3].split(' GMT')[0];
          offsetPart = parts[3].includes('GMT') ? parts[3].split('GMT')[1] : '+0000';
        } else {
          timePart = parts[3];
          offsetPart = '+0530'; // Default to IST if no timezone specified
        }

        // Combine into ISO-like string
        try {
          const dateTimeIso = new Date(`${datePart} ${timePart} GMT${offsetPart}`);
          return dateTimeIso;
        } catch (e) {
          console.error("Inner parse error:", e);
        }
      }
    }

    // If it's an object with start/end properties
    if (dateTimeStr && typeof dateTimeStr === 'object') {
      if (dateTimeStr.start && dateTimeStr.end) {
        return {
          start: parseDateTime(dateTimeStr.start),
          end: parseDateTime(dateTimeStr.end)
        };
      } else if (dateTimeStr instanceof Date) {
        return dateTimeStr;
      }
    }

    // Fallback - try direct parsing
    return new Date(dateTimeStr);
  } catch (e) {
    console.error("Failed to parse date:", dateTimeStr, e);
    return null;
  }
};

// Function to generate time slots (30-minute intervals)
const generateTimeSlots = (startTime, endTime) => {
  const slots = [];
  let current = new Date(startTime);

  while (current < endTime) {
    slots.push(new Date(current));
    // Add 30 minutes
    current = new Date(current.getTime() + (SLOT_DURATION * 60 * 1000));
  }

  return slots;
};

// Format time in 12-hour format with AM/PM
const formatTime = (date) => {
  return date.toLocaleTimeString('en-US', {
    timeZone: 'Asia/Kolkata', // IST timezone
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  }).toLowerCase();
};

// Format date in readable format
const formatDate = (date) => {
  return date.toLocaleDateString('en-US', {
    timeZone: 'Asia/Kolkata', // IST timezone
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    year: 'numeric'
  });
};

// Group existing appointments by date
const bookedSlotsByDate = {};

// Process all appointments from the input data
inputData.forEach((item, index) => {
  try {
    const startTime = parseDateTime(item.start || item.startTime);
    const endTime = parseDateTime(item.end || item.endTime);

    if (!startTime || !endTime) {
      console.log(`Skipping invalid appointment #${index}:`, item);
      return;
    }

    // Get date string to use as key (YYYY-MM-DD)
    const dateKey = startTime.toISOString().split('T')[0];

    if (!bookedSlotsByDate[dateKey]) {
      bookedSlotsByDate[dateKey] = [];
    }

    // Add this appointment to the booked slots for this date
    bookedSlotsByDate[dateKey].push({
      start: startTime,
      end: endTime,
      summary: item.name || item.summary || 'Booked'
    });

    console.log(`Processed appointment #${index} for ${dateKey}:`, 
      `${startTime.toISOString()} - ${endTime.toISOString()}`);

  } catch (error) {
    console.error(`Error processing appointment #${index}:`, item, error);
  }
});

// Calculate available time slots for next 7 days
const availabilityByDate = {};
const now = new Date();
const startDate = new Date(now);
startDate.setHours(0, 0, 0, 0); // Start from today

// Generate available slots for the next 7 days
for (let i = 0; i < 7; i++) {
  const currentDate = new Date(startDate);
  currentDate.setDate(currentDate.getDate() + i);

  // Skip weekends (0 = Sunday, 6 = Saturday)
  const dayOfWeek = currentDate.getDay();
  if (dayOfWeek === 0 || dayOfWeek === 6) {
    console.log(`Skipping weekend day: ${currentDate.toDateString()}`);
    continue;
  }

  const dateKey = currentDate.toISOString().split('T')[0];

  // Create date objects for start and end of business hours in the correct timezone
  const workdayStart = new Date(currentDate);
  // Convert IST business hours to UTC for internal calculations
  const workdayStartUtcHours = istToUtcHours(WORKDAY_START);
  workdayStart.setHours(workdayStartUtcHours, IST_OFFSET_MINUTES, 0, 0);

  const workdayEnd = new Date(currentDate);
  const workdayEndUtcHours = istToUtcHours(WORKDAY_END);
  workdayEnd.setHours(workdayEndUtcHours, IST_OFFSET_MINUTES, 0, 0);

  console.log(`Date: ${dateKey}, Business hours (UTC):`, 
    `${workdayStart.toISOString()} - ${workdayEnd.toISOString()}`);

  // Get booked slots for this date
  const bookedSlots = bookedSlotsByDate[dateKey] || [];

  // Sort booked slots by start time
  bookedSlots.sort((a, b) => a.start - b.start);

  // Find available time slots
  let availableSlots = [];
  let lastEndTime = new Date(workdayStart);

  // Check each booked slot and find gaps between them
  for (const bookedSlot of bookedSlots) {
    if (bookedSlot.start > lastEndTime) {
      // There's a gap between the last end time and this booking
      console.log(`Found gap: ${lastEndTime.toISOString()} - ${bookedSlot.start.toISOString()}`);
      const slotsInGap = generateTimeSlots(lastEndTime, bookedSlot.start);
      availableSlots = availableSlots.concat(slotsInGap);
    }
    // Update last end time
    lastEndTime = new Date(Math.max(lastEndTime.getTime(), bookedSlot.end.getTime()));
  }

  // Check if there's time after the last booking until end of business hours
  if (lastEndTime < workdayEnd) {
    console.log(`Found gap after last booking: ${lastEndTime.toISOString()} - ${workdayEnd.toISOString()}`);
    const slotsAfterLastBooking = generateTimeSlots(lastEndTime, workdayEnd);
    availableSlots = availableSlots.concat(slotsAfterLastBooking);
  }

  // Filter out any slots that are in the past
  availableSlots = availableSlots.filter(slot => slot > now);

  if (availableSlots.length > 0) {
    // Find continuous available ranges (wide open ranges)
    const wideOpenRanges = [];
    let rangeStart = availableSlots[0];
    let prevSlot = availableSlots[0];

    for (let j = 1; j < availableSlots.length; j++) {
      const currentSlot = availableSlots[j];
      const expectedNextTime = new Date(prevSlot.getTime() + (SLOT_DURATION * 60 * 1000));

      // If there's a gap, end the current range
      if (currentSlot.getTime() !== expectedNextTime.getTime()) {
        if (prevSlot.getTime() - rangeStart.getTime() >= (SLOT_DURATION * 2 * 60 * 1000)) {
          // Range has at least 3 slots (1 hour)
          wideOpenRanges.push({
            start: rangeStart,
            end: prevSlot
          });
        }
        rangeStart = currentSlot;
      }

      prevSlot = currentSlot;
    }

    // Check the last range
    if (prevSlot.getTime() - rangeStart.getTime() >= (SLOT_DURATION * 2 * 60 * 1000)) {
      wideOpenRanges.push({
        start: rangeStart,
        end: prevSlot
      });
    }

    availabilityByDate[dateKey] = {
      date: formatDate(currentDate),
      availableSlots: availableSlots.map(slot => formatTime(slot)),
      wideOpenRanges: wideOpenRanges.map(range => 
        `${formatTime(range.start)} to ${formatTime(range.end)}`)
    };
  } else {
    console.log(`No available slots for ${dateKey}`);
  }
}

// Format output as plaintext
const availableTimes = Object.values(availabilityByDate)
  .map(({ date, availableSlots, wideOpenRanges }) => {
    const times = availableSlots.map((time) => `- ${time}`).join('\n');
    const ranges = wideOpenRanges.length > 0
      ? `Wide Open Ranges:\n${wideOpenRanges.map((range) => `- ${range}`).join('\n')}`
      : "Wide Open Ranges: None";

    return `### ${date}\nAvailable Start Times:\n${times}\n\n${ranges}`;
  })
  .join('\n\n');

// Set the output
return {
  json: {
    availableTimes,
    debug: {
      workdayStartIST: WORKDAY_START,
      workdayEndIST: WORKDAY_END,
      workdayStartUTC: istToUtcHours(WORKDAY_START),
      workdayEndUTC: istToUtcHours(WORKDAY_END),
      inputDataCount: inputData.length,
      bookedSlotsByDate,
      availabilityByDate,
      currentTimeUTC: new Date().toISOString(),
      currentTimeIST: new Date().toLocaleString('en-US', {timeZone: 'Asia/Kolkata'})
    }
  }
};

// Get the current date and time in IST
const now = new Date();

// IST offset (UTC+5:30) in milliseconds
const istOffsetMs = 5.5 * 60 * 60 * 1000;

// Calculate IST time
const istTime = new Date(now.getTime() + istOffsetMs);

// Format IST time as YYYY-MM-DD HH:MM:SS
const year = istTime.getFullYear();
const month = String(istTime.getMonth() + 1).padStart(2, '0');
const day = String(istTime.getDate()).padStart(2, '0');
const hours = String(istTime.getHours()).padStart(2, '0');
const minutes = String(istTime.getMinutes()).padStart(2, '0');
const seconds = String(istTime.getSeconds()).padStart(2, '0');

const formattedDateTime = `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;

// Return the formatted IST time
return [
  {
    json: {
      currentTimeIST: formattedDateTime
    }
  }
];

const items = $input.all();
return items.map(item => {
  try {
    const originalData = item.json;

    // Get current IST time with better error handling
    const now = new Date();
    const istOffset = 5.5 * 60; // in minutes
    const utcTime = now.getTime() + (now.getTimezoneOffset() * 60000);
    const istTime = new Date(utcTime + (istOffset * 60000));

    // Add 1 hour to the current IST time
    const newScheduledDateTime = new Date(istTime.getTime() + (60 * 60 * 1000));

    // Format for Google Sheets
    const newScheduledDate = newScheduledDateTime.getFullYear() + '-'
      + String(newScheduledDateTime.getMonth() + 1).padStart(2, '0') + '-'
      + String(newScheduledDateTime.getDate()).padStart(2, '0');

