        originalCallTime: istTime.toISOString()
      }
    };
  } catch (error) {
    console.error('Error calculating new scheduled time:', error);
    return {
      json: {
        ...item.json,
        newScheduledDate: null,
        newScheduledTime: null,
        newCallStatus: 'Error',
        rescheduleError: error.message
      }
    };
  }
});

const input = $input.first().json;

// Safely access nested property using optional chaining
const successEvaluation = input?.originalData?.costBreakdown?.analysisCostBreakdown?.successEvaluation;

if (successEvaluation) {
  return [
    {
      json: input
    }
  ];
} else {
  // If successEvaluation is falsy or any property is missing, return an empty array
  return [];
}

const items = $input.all();

function normalizeTime(text) {
    // Get current time in IST
    const now = new Date();
    const istNow = new Date(now.getTime() + (5.5 * 60 * 60 * 1000)); // Add 5:30 hours to UTC

    // Create result date starting from IST current time
    let result = new Date(istNow);

    const lower = text.toLowerCase().trim();

    console.log("normalizeTime input text:", text);
    console.log("Current IST time:", istNow.toISOString());

    // Working Hours Constants
    const workingHoursStart = 10; // 10 AM
    const workingHoursEnd = 18;   // 6 PM

    // 1. Determine Base Date
    let isTomorrow = false;
    let isNextWeek = false;

    if (lower.includes("tomorrow")) {
        result.setUTCDate(result.getUTCDate() + 1);
        isTomorrow = true;
    } else if (lower.includes("next week")) {
        result.setUTCDate(result.getUTCDate() + 7);
        isNextWeek = true;
    }

    // 2. Enhanced Time Parsing with better regex
    const timePatterns = [
        // Matches: "2 pm", "2pm", "2 PM", "14:30", "2:30 pm", etc.
        /\b(\d{1,2})(?::(\d{2}))?\s*(am|pm|AM|PM)\b/,
        // Matches: "2 o'clock", "14 o'clock"
        /\b(\d{1,2})\s*o'?clock\b/,
        // Matches: 24-hour format "14:30", "09:15"
        /\b(\d{1,2}):(\d{2})\b/,
        // Matches: just numbers that could be hours "2", "14"
        /\b(\d{1,2})\b/
    ];

    let timeFound = false;
    let hour = null;
    let minutes = 0;
    let isAM = false;
    let isPM = false;

    // Try each pattern
    for (const pattern of timePatterns) {
        const match = lower.match(pattern);
        if (match) {
            hour = parseInt(match[1], 10);
            minutes = match[2] ? parseInt(match[2], 10) : 0;

            // Check for AM/PM
            if (match[3]) {
                const ampm = match[3].toLowerCase();
                isAM = ampm === 'am';
                isPM = ampm === 'pm';
            }

            timeFound = true;
            console.log("Time match found:", match, "Hour:", hour, "Minutes:", minutes, "AM:", isAM, "PM:", isPM);
            break;
        }
    }

    if (timeFound && hour !== null) {
        // Handle 12-hour to 24-hour conversion
        if (isPM && hour !== 12) {
            hour += 12;
        } else if (isAM && hour === 12) {
            hour = 0; // 12 AM = midnight
        }

        // If no AM/PM specified, use intelligent inference
        if (!isAM && !isPM) {
            const currentHour = result.getUTCHours();

            // For ambiguous times, prefer PM for afternoon/evening context
            if (hour >= 1 && hour <= 11) {
                // If it's tomorrow/next week, or current time suggests PM
                if (isTomorrow || isNextWeek || currentHour >= 12) {
                    // Prefer PM unless it would make the time invalid or unreasonable
                    if (hour + 12 <= 23) {
                        hour += 12;
                    }
                }
                // For times like "2" when it's currently afternoon, assume PM
                else if (currentHour >= 12 && hour <= 6) {
                    hour += 12;
                }
            }
        }

        // Set the parsed time (using UTC methods to avoid timezone issues)
        if (hour >= 0 && hour <= 23 && minutes >= 0 && minutes <= 59) {
            result.setUTCHours(hour, minutes, 0, 0);
        }

    } else {
        // Handle relative times
        if (lower.includes("after an hour") || lower.includes("in an hour") || lower.includes("call back after an hour")) {
            result.setUTCHours(result.getUTCHours() + 1);
        } else if (lower.includes("after 30 minutes") || lower.includes("in 30 minutes")) {
            result.setUTCMinutes(result.getUTCMinutes() + 30);
        } else if (lower.includes("after") && lower.includes("minutes")) {
            // Extract number of minutes
            const minutesMatch = lower.match(/after\s+(\d+)\s+minutes/);
            if (minutesMatch) {
                const mins = parseInt(minutesMatch[1], 10);
                result.setUTCMinutes(result.getUTCMinutes() + mins);
            }
        } else if (lower.includes("in") && lower.includes("minutes")) {
            // Extract number of minutes
            const minutesMatch = lower.match(/in\s+(\d+)\s+minutes/);
            if (minutesMatch) {
                const mins = parseInt(minutesMatch[1], 10);
                result.setUTCMinutes(result.getUTCMinutes() + mins);
            }
        } else if (isTomorrow || isNextWeek) {
            // Default to 10 AM for tomorrow/next week
            result.setUTCHours(workingHoursStart, 0, 0, 0);
        } else {
            // Default: 1 hour from now
            result.setUTCHours(result.getUTCHours() + 1);
        }
    }

    // Apply Working Hours Constraint
    let finalHour = result.getUTCHours();
    let finalMinutes = result.getUTCMinutes();

    // Adjust if outside working hours
    if (finalHour < workingHoursStart) {
        result.setUTCHours(workingHoursStart, 0, 0, 0);
    } else if (finalHour > workingHoursEnd || (finalHour === workingHoursEnd && finalMinutes > 0)) {
        result.setUTCDate(result.getUTCDate() + 1);
        result.setUTCHours(workingHoursStart, 0, 0, 0);
