                isPastDate: false,
                error: 'Missing or invalid scheduled date',
                normalizedToday: istTime.toISOString(),
                normalizedScheduledDate: null
            }
        };
    }

    if (typeof dateString === 'string' && dateString.includes('-')) {
        // Split and parse YYYY-MM-DD format explicitly
        const parts = dateString.split('-');

        // Validate parts
        if (parts.length !== 3) {
            console.log(`Invalid date format: ${dateString}`);
            return {
                json: {
                    ...json,
                    isToday: false,
                    isWithinTimeRange: false,
                    isPastDate: false,
                    error: 'Invalid date format',
                    normalizedToday: istTime.toISOString(),
                    normalizedScheduledDate: null
                }
            };
        }

        const year = parseInt(parts[0]);
        const month = parseInt(parts[1]) - 1; // JavaScript months are 0-indexed
        const day = parseInt(parts[2]);

        // Validate parsed values
        if (isNaN(year) || isNaN(month) || isNaN(day) || 
            year < 1900 || year > 2100 || 
            month < 0 || month > 11 || 
            day < 1 || day > 31) {
            console.log(`Invalid date values: year=${year}, month=${month}, day=${day}`);
            return {
                json: {
                    ...json,
                    isToday: false,
                    isWithinTimeRange: false,
                    isPastDate: false,
                    error: 'Invalid date values',
                    normalizedToday: istTime.toISOString(),
                    normalizedScheduledDate: null
                }
            };
        }

        scheduledDate = new Date(year, month, day);
    } else {
        scheduledDate = new Date(dateString);
