    if (scheduledTime && scheduledTime.toString().includes(':')) {
        const timeParts = scheduledTime.toString().split(':');

        if (timeParts.length >= 2) {
            const hours = parseInt(timeParts[0]);
            const minutes = parseInt(timeParts[1]);

            // Validate time values
            if (!isNaN(hours) && !isNaN(minutes) && 
                hours >= 0 && hours <= 23 && 
                minutes >= 0 && minutes <= 59) {
                // Set the time on the scheduled date
                scheduledDate.setHours(hours, minutes, 0, 0);
            } else {
                console.log(`Invalid time values: hours=${hours}, minutes=${minutes}`);
                // Use default time if invalid
                scheduledDate.setHours(0, 0, 0, 0);
            }
        }
    }

    // Validate the final scheduled date again
    if (isNaN(scheduledDate.getTime())) {
        console.log(`Invalid final scheduled date`);
        return {
            json: {
                ...json,
                isToday: false,
                isWithinTimeRange: false,
                isPastDate: false,
                error: 'Invalid final scheduled date',
                normalizedToday: istTime.toISOString(),
                normalizedScheduledDate: null
            }
        };
    }

    // Calculate the scheduled date/time in UTC
    const scheduledDateTimeUTC = new Date(scheduledDate.getTime() - istOffsetMs);

    // Create normalized dates for date comparison (without time)
    const normalizedToday = new Date(istTime.getFullYear(), istTime.getMonth(), istTime.getDate());
    const normalizedScheduledDate = new Date(scheduledDate.getFullYear(), scheduledDate.getMonth(), scheduledDate.getDate());

    // Validate normalized dates
    if (isNaN(normalizedToday.getTime()) || isNaN(normalizedScheduledDate.getTime())) {
        console.log(`Invalid normalized dates`);
        return {
            json: {
                ...json,
                isToday: false,
                isWithinTimeRange: false,
                isPastDate: false,
                error: 'Invalid normalized dates',
                normalizedToday: istTime.toISOString(),
                normalizedScheduledDate: null
            }
        };
    }

    // Check if scheduled date is today
    const isToday = normalizedToday.getTime() === normalizedScheduledDate.getTime();

    // Calculate time difference in minutes
    const timeDiffMs = scheduledDateTimeUTC.getTime() - now.getTime();
    const diffInMinutes = Math.abs(timeDiffMs) / (1000 * 60);

    // Check if scheduled time is in the past or future
    const isInFuture = scheduledDate > istTime;

    let isPast = false;
    let isWithinTimeRange = false;

    if (isToday) {
        isPast = false;
        isWithinTimeRange = diffInMinutes <= 10;
    } else {
        isPast = scheduledDate < istTime;
        isWithinTimeRange = false; // Not today, so not within time range
    }

    // Detailed Debugging Output
    const debugInfo = {
        CallStatus: json.CallStatus,
        CurrentTimeUTC: now.toISOString(),
        CurrentTimeIST: istTime.toISOString(),
        ScheduledDateString: dateString,
        ScheduledTimeString: scheduledTime,
