        ScheduledDateTimeUTC: scheduledDateTimeUTC.toISOString(),
        NormalizedToday: normalizedToday.toISOString(),
        NormalizedScheduledDate: normalizedScheduledDate.toISOString(),
        isToday: isToday,
        TimeDiffMinutes: diffInMinutes,
        isWithinTimeRange: isWithinTimeRange,
        isInFuture: isInFuture,
        isPast: isPast
    };

    console.log("Debug Info:", debugInfo);

    // Return the item with all original data plus new calculated fields
    return {
        json: {
            ...json,
            isToday: isToday,
            isWithinTimeRange: isWithinTimeRange,
            isPastDate: isPast,
            normalizedToday: normalizedToday.toISOString(),
            normalizedScheduledDate: normalizedScheduledDate.toISOString(),
            debug: debugInfo
        }
    };
});

