const item = $input.first().json;
const summary = (item.callSummary || "").toLowerCase();
const transcript = (item.callTranscript || "").toLowerCase();

const text = summary + " " + transcript;

const callbackPhrases = [
    'call me later', 'call back', 'not now', 'call me after sometime', 
    'right now i am busy', 'call me today at', 'i am busy', 'call tomorrow',
    'call me after', 'call me at', 'busy right now', 'call me back',
    'call later', 'call me in', 'call after'
];
// const meetingPhrases = ['demo', 'meeting', 'pre-sales', 'sales person', 'book', 'schedule'];

let intent = 'unknown';
if (callbackPhrases.some(p => text.includes(p))) {
  intent = 'callback';
} 
// else if (meetingPhrases.some(p => text.includes(p))) {
//   intent = 'meeting';
// }

return [{
  json: {
    ...item,
    detectedIntent: intent
  }
}];
